# Generated by openai (gpt-5.4)
# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import os
import uuid
import threading
import traceback
import numpy as np
import pandas as pd
import tensorflow as tf
from werkzeug.utils import secure_filename

app = Flask(__name__)

BASE_DIR = os.path.dirname(os.path.abspath(__file__))
UPLOAD_DIR = os.path.join(BASE_DIR, "uploads")
MODEL_DIR = os.path.join(BASE_DIR, "model_store")
DATASET_PATH = os.path.join(BASE_DIR, "community_dataset.csv")
MODEL_PATH = os.path.join(MODEL_DIR, "community_model.keras")
META_PATH = os.path.join(MODEL_DIR, "metadata.json")

os.makedirs(UPLOAD_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

TRAINING_LOCK = threading.Lock()
TRAINING_STATUS = {
    "is_training": False,
    "last_error": None,
    "last_metrics": None,
    "last_rows_used": 0,
    "last_model_path": None,
}

ALLOWED_EXTENSIONS = {"csv"}

REQUIRED_COLUMNS = {"label"}
IMAGE_FEATURE_PREFIX = "pixel_"

def allowed_file(filename):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in ALLOWED_EXTENSIONS

def load_existing_dataset():
    if os.path.exists(DATASET_PATH):
        return pd.read_csv(DATASET_PATH)
    return pd.DataFrame()

def save_dataset(df):
    df.to_csv(DATASET_PATH, index=False)

def validate_and_normalize_csv(df):
    if "label" not in df.columns:
        raise ValueError("CSV must contain a 'label' column")
    feature_cols = [c for c in df.columns if c.startswith(IMAGE_FEATURE_PREFIX)]
    if not feature_cols:
        raise ValueError("CSV must contain feature columns prefixed with 'pixel_'")
    normalized = df.copy()
    normalized = normalized.dropna()
    normalized["label"] = normalized["label"].astype(str)
    for col in feature_cols:
        normalized[col] = pd.to_numeric(normalized[col], errors="coerce")
    normalized = normalized.dropna()
    if normalized.empty:
        raise ValueError("No valid rows after cleaning")
    return normalized

def merge_dataset(new_df):
    existing = load_existing_dataset()
    if existing.empty:
        combined = new_df
    else:
        missing_in_existing = [c for c in new_df.columns if c not in existing.columns]
        missing_in_new = [c for c in existing.columns if c not in new_df.columns]
        for c in missing_in_existing:
            existing[c] = 0.0 if c.startswith(IMAGE_FEATURE_PREFIX) else ""
        for c in missing_in_new:
            new_df[c] = 0.0 if c.startswith(IMAGE_FEATURE_PREFIX) else ""
        combined = pd.concat([existing, new_df], ignore_index=True)
    feature_cols = sorted([c for c in combined.columns if c.startswith(IMAGE_FEATURE_PREFIX)])
    ordered_cols = ["label"] + feature_cols
    combined = combined[ordered_cols]
    combined = combined.dropna()
    save_dataset(combined)
    return combined

def build_model(input_dim, num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(input_dim,)),
        tf.keras.layers.Dense(256, activation="relu"),
        tf.keras.layers.Dropout(0.25),
        tf.keras.layers.Dense(128, activation="relu"),
        tf.keras.layers.Dropout(0.25),
        tf.keras.layers.Dense(num_classes, activation="softmax"),
    ])
    model.compile(
        optimizer="adam",
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"],
    )
    return model

def train_model_from_dataset():
    with TRAINING_LOCK:
        TRAINING_STATUS["is_training"] = True
        TRAINING_STATUS["last_error"] = None
        try:
            if not os.path.exists(DATASET_PATH):
                raise FileNotFoundError("No dataset found")
            df = pd.read_csv(DATASET_PATH)
            df = validate_and_normalize_csv(df)
            feature_cols = sorted([c for c in df.columns if c.startswith(IMAGE_FEATURE_PREFIX)])
            X = df[feature_cols].astype("float32").values
            if X.max() > 1.0:
                X = X / 255.0
            labels = sorted(df["label"].unique().tolist())
            label_to_idx = {label: idx for idx, label in enumerate(labels)}
            y = df["label"].map(label_to_idx).astype("int32").values

            if len(np.unique(y)) < 2:
                raise ValueError("Need at least 2 classes to train")

            val_split = 0.2 if len(df) >= 10 else 0.0
            model = build_model(X.shape[1], len(labels))

            callbacks = [
                tf.keras.callbacks.EarlyStopping(
                    monitor="val_loss" if val_split > 0 else "loss",
                    patience=3,
                    restore_best_weights=True,
                )
            ]

            history = model.fit(
                X,
                y,
                validation_split=val_split,
                epochs=20,
                batch_size=min(32, max(4, len(df))),
                verbose=0,
                callbacks=callbacks,
                shuffle=True,
            )

            model.save(MODEL_PATH)

            metadata = {
                "labels": labels,
                "feature_columns": feature_cols,
                "num_rows": int(len(df)),
                "input_dim": int(X.shape[1]),
            }
            import json
            with open(META_PATH, "w", encoding="utf-8") as f:
                json.dump(metadata, f)

            last_metrics = {}
            for k, v in history.history.items():
                if v:
                    last_metrics[k] = float(v[-1])

            TRAINING_STATUS["last_metrics"] = last_metrics
            TRAINING_STATUS["last_rows_used"] = int(len(df))
            TRAINING_STATUS["last_model_path"] = MODEL_PATH
        except Exception as e:
            TRAINING_STATUS["last_error"] = f"{type(e).__name__}: {str(e)}"
            traceback.print_exc()
        finally:
            TRAINING_STATUS["is_training"] = False

@app.route("/health", methods=["GET"])
def health():
    return jsonify({"status": "ok"})

@app.route("/upload", methods=["POST"])
def upload():
    if "file" not in request.files:
        return jsonify({"error": "No file provided"}), 400
    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400
    if not allowed_file(file.filename):
        return jsonify({"error": "Only CSV uploads are allowed"}), 400

    filename = secure_filename(file.filename)
    saved_name = f"{uuid.uuid4().hex}_{filename}"
    saved_path = os.path.join(UPLOAD_DIR, saved_name)
    file.save(saved_path)

    try:
        df = pd.read_csv(saved_path)
        df = validate_and_normalize_csv(df)
        combined = merge_dataset(df)
        return jsonify({
            "message": "Upload accepted and merged into community dataset",
            "rows_added": int(len(df)),
            "total_rows": int(len(combined)),
        })
    except Exception as e:
        return jsonify({"error": str(e)}), 400

@app.route("/contribute", methods=["POST"])
def contribute():
    if request.is_json:
        payload = request.get_json()
        if isinstance(payload, dict):
            records = payload.get("records", [])
        elif isinstance(payload, list):
            records = payload
        else:
            return jsonify({"error": "Invalid JSON payload"}), 400
        try:
            df = pd.DataFrame(records)
            df = validate_and_normalize_csv(df)
            combined = merge_dataset(df)
            return jsonify({
                "message": "Contribution accepted",
                "rows_added": int(len(df)),
                "total_rows": int(len(combined)),
            })
        except Exception as e:
            return jsonify({"error": str(e)}), 400

    if "file" in request.files:
        return upload()

    return jsonify({"error": "Provide JSON records or CSV file"}), 400

@app.route("/train", methods=["POST"])
def train():
    if TRAINING_STATUS["is_training"]:
        return jsonify({"message": "Training already in progress"}), 409
    thread = threading.Thread(target=train_model_from_dataset, daemon=True)
    thread.start()
    return jsonify({"message": "Training started"})

@app.route("/status", methods=["GET"])
def status():
    return jsonify(TRAINING_STATUS)

@app.route("/predict", methods=["POST"])
def predict():
    if not os.path.exists(MODEL_PATH) or not os.path.exists(META_PATH):
        return jsonify({"error": "Model not trained yet"}), 400

    import json
    with open(META_PATH, "r", encoding="utf-8") as f:
        metadata = json.load(f)

    model = tf.keras.models.load_model(MODEL_PATH)
    labels = metadata["labels"]
    feature_columns = metadata["feature_columns"]

    if request.is_json:
        payload = request.get_json()
        if isinstance(payload, dict):
            records = payload.get("records", [payload])
        elif isinstance(payload, list):
            records = payload
        else:
            return jsonify({"error": "Invalid JSON payload"}), 400
        df = pd.DataFrame(records)
    elif "file" in request.files:
        file = request.files["file"]
        if file.filename == "":
            return jsonify({"error": "Empty filename"}), 400
        df = pd.read_csv(file)
    else:
        return jsonify({"error": "Provide JSON records or CSV file"}), 400

    for col in feature_columns:
        if col not in df.columns:
            df[col] = 0.0
    extra_cols = [c for c in df.columns if c in feature_columns]
    df = df[feature_columns if feature_columns else extra_cols]

    for col in feature_columns:
        df[col] = pd.to_numeric(df[col], errors="coerce")
    df = df.fillna(0.0)

    X = df.astype("float32").values
    if X.size == 0:
        return jsonify({"error": "No valid feature rows supplied"}), 400
    if X.max() > 1.0:
        X = X / 255.0

    probs = model.predict(X, verbose=0)
    preds = np.argmax(probs, axis=1)

    results = []
    for i, pred_idx in enumerate(preds):
        results.append({
            "predicted_label": labels[int(pred_idx)],
            "confidence": float(np.max(probs[i])),
            "probabilities": {labels[j]: float(probs[i][j]) for j in range(len(labels))}
        })

    return jsonify({"predictions": results})

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=5000)